const API = 'https://ecommerce-backend-ss1r.onrender.com/api/v1';

function imgs(slug: string, count = 7) {
  return Array.from({ length: count }, (_, i) => ({
    url: `https://picsum.photos/seed/${slug}-${i + 1}/600/800`,
    alt: `${slug} image ${i + 1}`,
    isPrimary: i === 0,
    displayOrder: i,
  }));
}

function variants(sku: string, sizes: string[], colors: { name: string; hex: string }[], price: number) {
  const v: any[] = [];
  for (const c of colors) {
    for (const s of sizes) {
      v.push({ size: s, color: c.name, colorHex: c.hex, sku: `${sku}-${c.name.toUpperCase().slice(0, 3)}-${s}`, price, stock: Math.floor(Math.random() * 40) + 5 });
    }
  }
  return v;
}

