async function login(): Promise<string> {
  const creds = [
    { email: 'rajakajaykumar686@gmail.com', password: '@Kareena.com201522' },
    { email: 'admin@storename.com', password: 'admin123' },
  ];
  for (const c of creds) {
    try {
      const res = await fetch(`${API}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(c),
      });
      const data: any = await res.json();
      if (data.success && data.data?.accessToken) {
        console.log(`Logged in as ${c.email}`);
        return data.data.accessToken;
      }
    } catch {}
  }
  throw new Error('Login failed with all credentials');
}

async function apiGet(path: string, token: string): Promise<any> {
  const res = await fetch(`${API}${path}`, { headers: { Authorization: `Bearer ${token}` } });
  return res.json();
}

async function apiPost(path: string, body: any, token: string): Promise<any> {
  const res = await fetch(`${API}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
    body: JSON.stringify(body),
  });
  return res.json();
}

async function main() {
  console.log('=== Seeding 100 Products via API ===\n');

  const token = await login();

  const catRes: any = await apiGet('/categories', token);
  const cats: any[] = catRes.data || catRes || [];
  const catMap: Record<string, string> = {};
  for (const c of cats) catMap[c.slug] = c.id;
  console.log(`Found ${cats.length} categories`);

  const brandRes: any = await apiGet('/brands', token);
  const brands: any[] = brandRes.data || brandRes || [];
  const brandMap: Record<string, string> = {};
  for (const b of brands) brandMap[b.slug] = b.id;
  console.log(`Found ${brands.length} brands`);

  let created = 0;
  let failed = 0;
  let skipped = 0;

  for (const p of products) {
    const catId = catMap[p.catSlug];
    if (!catId) {
      console.log(`  SKIP: category "${p.catSlug}" not found for "${p.name}"`);
      skipped++;
      continue;
    }

    const body = {
      name: p.name,
      description: p.desc,
      shortDescription: p.short,
      tags: p.tags,
      categoryId: catId,
      brandId: brandMap[p.brandSlug] || undefined,
      gender: p.gender,
      basePrice: p.base,
      salePrice: p.sale,
      sku: p.sku,
      status: 'PUBLISHED',
      isActive: true,
      isFeatured: p.feat,
      isNewArrival: p.newArr,
      isBestSeller: p.best,
      isTrending: p.trend,
      fabric: p.fabric,
      material: p.material,
      washCare: p.wash,
      hsnCode: '6109',
      gstRate: 12,
      returnAvailable: true,
      returnPeriod: 30,
      exchangeAvailable: true,
      warrantyPeriod: 'Standard Quality',
      couponEligible: true,
      flashSale: p.flash,
      festivalOffer: p.fest,
      metaTitle: p.name,
      metaDescription: p.short,
      metaKeywords: p.tags,
      images: imgs(p.sku.toLowerCase(), p.imgCount),
      variants: variants(p.sku, p.sizes, p.colors, p.sale),
    };

    try {
      const res: any = await apiPost('/admin/products', body, token);
      if (res.success) {
        created++;
        if (created % 10 === 0) console.log(`  Created ${created} products...`);
      } else if (res.message && res.message.includes('many requests')) {
        // Rate limited — wait 15s and retry once
        console.log(`  Rate limited on [${p.sku}], waiting 15s...`);
        await new Promise((r) => setTimeout(r, 15000));
        const retry: any = await apiPost('/admin/products', body, token);
        if (retry.success) {
          created++;
          console.log(`  Retry OK: ${p.name}`);
        } else {
          console.log(`  RETRY FAIL [${p.sku}]: ${retry.message || 'unknown'}`);
          failed++;
        }
      } else {
        console.log(`  FAIL [${p.sku}]: ${res.message || 'unknown error'}`);
        failed++;
      }
    } catch (err: any) {
      console.log(`  ERROR [${p.sku}]: ${err.message}`);
      failed++;
    }

    // Delay between requests to avoid rate limiting
    await new Promise((r) => setTimeout(r, 2000));
  }

  console.log(`\n=== DONE ===`);
  console.log(`Created: ${created}`);
  console.log(`Failed: ${failed}`);
  console.log(`Skipped: ${skipped}`);
  console.log(`Total attempted: ${products.length}`);
}

main().catch((e) => {
  console.error('FATAL:', e);
  process.exit(1);
});
